For #393

Here's the gist of what a pico export looks like. See the `engine.test.js` for a complete example.
```js
{
    version: "0.46.0",// engine core version so we can support backwards compatibility
    policies: {
     // policy definitions the pico channels depend on
    },
    rulesets: {
      // ruleset definition the pico depends on
    },
    pico: {
      id: 'id0',
      parent_id: null,
      admin_eci: 'id1',
      channels: {
        'id1': { id: 'id1', name: 'admin', type: 'secret', policy_id: 'allow-all-policy', sovrin: { did: 'id1', verifyKey: 'verifyKey_id1', secret: { seed: 'seed_id1', signKey: 'signKey_id1' } } }
        // ...
      },
      entvars: {
       // ent var values by rid
      },
      state_machine: {
        // current value of each rule's state_machine
      },
      aggregator_var: {
        // current value of any event aggregation variables
      },
      children: [
        // any child pico's
      ]
    }
  }
```

this seems to work and doesn't break any pre-existing tests

